var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"NETBLINK SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>\\nIDENTIFICATION: <color=#ffd34c>CONFIRMED</color>\\nCCN No. TPM002M000140-01: <color=#ffd34c>이유미</color>","JPN":"NETBLINK SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>\\nIDENTIFICATION：<color=#ffd34c>CONFIRMED</color>\\nCCN No. TPM002M000140-01：<color=#ffd34c>カスカベ・ユミ</color>","ENG":"NETBLINK SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>\\nIDENTIFICATION: <color=#ffd34c>CONFIRMED</color>\\nCCN No. TPM002M000140-01: <color=#ffd34c>Lee Yumi</color>","TWN":"NETBLINK SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>\\nIDENTIFICATION: <color=#ffd34c>CONFIRMED</color>\\nCCN No.TPM002M000140-01: <color=#ffd34c>李悠美</color>"},"stage":{"bg":"BLACK","bgm":null,"filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"INTERVIEWER_NPC_POLICE_NULL","text":{"KOREA":"그럼 마지막 질문입니다.","JPN":"では、最後の質問です。","ENG":"Okay, last question.","TWN":"那這是最後一個問題。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"INTERVIEWER_NPC_POLICE_NULL","text":{"KOREA":"이유미 씨는 정의가 무엇이라고 생각하십니까?","JPN":"カスカベ・ユミさんが思う正義は何ですか？","ENG":"What does justice mean to you, Ms. Lee?","TWN":"對悠美小姐來說，正義是什麼？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"아주 쉬운 질문이군요.","JPN":"とても簡単な質問ですね。","ENG":"That's an easy one.","TWN":"這問題太簡單了。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"정의란 악을 심판하는 것입니다.","JPN":"正義とは悪を裁くことです。","ENG":"Justice is bringing judgment upon evil.","TWN":"正義就是制裁邪惡。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"철저하고 무자비하게 범죄자를 뿌리 뽑는 것만이 정의라고 할 수 있습니다.","JPN":"徹底的かつ無慈悲に犯罪者を滅ぼすことのみが正義だと思います。","ENG":"Justice means thoroughly and mercilessly eradicating all crime.","TWN":"只有徹底地將罪犯無情根除，才能稱之為是正義。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"INTERVIEWER_NPC_POLICE_NULL","text":{"KOREA":"음...... 그렇군요. 알겠습니다.","JPN":"うむ……そうですか。わかりました。","ENG":"Hmm... I see. Duly noted.","TWN":"呃……原來如此，我知道了。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"INTERVIEWER_NPC_POLICE_NULL","text":{"KOREA":"면접결과는 추후에 통보해드리도록 하겠습니다.","JPN":"面接結果は後ほどお知らせします。","ENG":"We'll be in touch regarding your interview results.","TWN":"面試的結果會在之後會通知您。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"INTERVIEWER_NPC_POLICE_NULL","text":{"KOREA":"정말 괜찮을까요?","JPN":"本当に大丈夫でしょうか？","ENG":"Are you sure about this?","TWN":"真的沒問題嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"INTERVIEWER_NPC_POLICE_NULL","text":{"KOREA":"아무리 최근에 경찰 지원자가 부족하다지만 이 정도로 기본 소양이 부족한 사람을 채용하는 건 문제가 될 수도 있습니다.","JPN":"いくら最近警察志願者が減ってきているとしても、これほど基本的な職業素養が足りない者を採用するのは問題になるかもしれません。","ENG":"I know we've been short on applicants lately, but hiring someone with such an unfit ideology could prove problematic for the force later.","TWN":"就算最近的警察志願者不足，但聘用這種缺乏基本素養的人會出問題吧。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGENCY_NPC_POLICE_NULL","text":{"KOREA":"어쩔 수 없지. 자네 말대로 인력이 너무 부족해.","JPN":"仕方ないんだ。君の言うとおり、警察は深刻な人手不足に直面している。","ENG":"We don't really have a choice. As you've said, we're really short on manpower.","TWN":"沒辦法啊。就像你說的一樣，最近實在是太缺人手了。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENCY_NPC_POLICE_NULL","text":{"KOREA":"이미 공권력의 대부분이 군대에서 민간군사기업 쪽으로 넘어간 게 현실이야.","JPN":"すでに主な公権力が軍から民間軍事企業の手に墜ちたのが現実だ。","ENG":"It doesn't help that a lion's share of law enforcement personnel transferred over to private military companies already.","TWN":"現在的公權力已經從軍方轉移到私人軍事公司了。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AGENCY_NPC_POLICE_NULL","text":{"KOREA":"변화가 없다면 치안 유지마저 경찰의 손에서 떠날 수도 있네.","JPN":"変化がないと、治安維持さえも警察の手を離れるかもしれない。","ENG":"If we can't change that, the police may lose its responsibility for maintaining law and order.","TWN":"如果沒有改變的話，警察可能連維護治安的權力都會失去。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"AGENCY_NPC_POLICE_NULL","text":{"KOREA":"그런 건 용납할 수 없어.","JPN":"そんなことは許せない。","ENG":"I will not let it ever come to that if I can help it.","TWN":"我無法忍受這種事情發生。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGENCY_NPC_POLICE_NULL","text":{"KOREA":"거기다가 자발적으로 지원한 카운터 능력자 아닌가?","JPN":"それに、自ら志願したカウンター能力者ではないか。","ENG":"Besides, this is a Counter who voluntarily applied.","TWN":"而且她還是自願來幫忙的制裁者啊？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGENCY_NPC_POLICE_NULL","text":{"KOREA":"이번 기회를 놓치면 다음 카운터 채용이 언제일지는 기약도 없으니까.","JPN":"このチャンスを逃したら、次のカウンター採用がいつになるかわからないしな。","ENG":"If we miss our chance now, there's no telling when we'll be able to hire another one.","TWN":"如果錯過這次機會，下次能錄用制裁者不知道要等到什麼時候。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"INTERVIEWER_NPC_POLICE_NULL","text":{"KOREA":"하지만 그래도......","JPN":"ですが……","ENG":"But still...","TWN":"但就算這樣……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGENCY_NPC_POLICE_NULL","text":{"KOREA":"미안하지만 채용은 결정사항일세. 이건 위에서 결정된 일이야.","JPN":"すまないが、採用は決定事項だ。これは上からの指示だ。","ENG":"Sorry, but the decision is final. This comes from way beyond my pay grade.","TWN":"非常抱歉，但錄取她已經是既定事項，這是上面的決定。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"INTERVIEWER_NPC_POLICE_NULL","text":{"KOREA":"그런가요? 그렇다면 어쩔 수 없겠네요......","JPN":"そうなんですか？　なら仕方ありませんね……","ENG":"Is that so? I suppose there's nothing I can do about it then...","TWN":"是嗎？那就沒辦法了呢……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGENCY_NPC_POLICE_NULL","text":{"KOREA":"피할 수 없다면 긍정적으로 생각하게.","JPN":"避けることができないなら、前向きに考えようじゃないか。","ENG":"If you can't avoid it, try to think of it in a more constructive way.","TWN":"既然無法避免的話，那就往好處想吧。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AGENCY_NPC_POLICE_NULL","text":{"KOREA":"부족한 점이 있다면 채워줄 만한 사람이 있는 곳으로 보내면 될 일이야.","JPN":"あのカウンターが至らぬのなら、不足を満たしてくれる人がいる部署に配置すればいい。","ENG":"If she's lacking in some way, we can always assign her with someone who can supplement such gaps.","TWN":"如果她有什麼不足的地方，就看哪個部門裡有能夠彌補她缺點的人，把她送過去就行了。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"INTERVIEWER_NPC_POLICE_NULL","text":{"KOREA":"채워줄 만한 사람이요? 생각해 두신 곳이 있나 보죠?","JPN":"満たしてくれる人ですか？　お考えの部署があるのでしょうか？","ENG":"Someone who can supplement her gaps? I suppose you already have someone in mind?","TWN":"彌補她缺點的人嗎？看來你有想好的部門啦？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGENCY_NPC_POLICE_NULL","text":{"KOREA":"......카운터 수사 전담반에 인력 충원이 안 된지도 꽤 오래 됐지.","JPN":"……カウンター捜査担当班が、しばらく補充されてないようだな。","ENG":"It's been a while since we've had any new hires for the Counter crimes unit.","TWN":"……制裁者調查專案組好像已經很久沒有補充人才了。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"INTERVIEWER_NPC_POLICE_NULL","text":{"KOREA":"4기동 말입니까? 확실히 어울리긴 하지만...... 괜찮을까요?","JPN":"第4特別機動捜査隊ですか？　確かに合いそうですが……大丈夫でしょうか？","ENG":"You mean SWAT 4? She sure does seem like the right fit for that... But is this a good idea?","TWN":"第四機動隊嗎？確實挺適合的……但沒問題嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGENCY_NPC_POLICE_NULL","text":{"KOREA":"거기에 있는 강소영 경위라면 내가 좀 알지.","JPN":"あそこにいるマエカワ・ナツミ警部補をよく知っているのさ。","ENG":"I'm well acquainted with Lieutenant Kang over there.","TWN":"那邊的姜素英警衛，我對她略有耳聞。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AGENCY_NPC_POLICE_NULL","text":{"KOREA":"그 친구가 사고를 좀 많이 치긴 해도, 확실히 배울 점은 많을 거야.","JPN":"マエカワ警部補はいろいろやらかすが、学ぶところが多い者だ。","ENG":"She may be quite the troublemaker, but our new Counter will have much to learn from her as well.","TWN":"雖然那位朋友闖的禍有點多，但確實有很多可以學習的地方。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"INTERVIEWER_NPC_POLICE_NULL","text":{"KOREA":"......알겠습니다.","JPN":"……わかりました。","ENG":"Understood.","TWN":"……知道了。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"INTERVIEWER_NPC_POLICE_NULL","text":{"KOREA":"그럼 이유미 순경은 4기동대로 배치하겠습니다.","JPN":"ではカスカベ・ユミ巡査は第4特別機動捜査隊に配置します。","ENG":"Then I'll have Constable Lee Yumi assigned to Police SWAT 4.","TWN":"那我會把李悠美巡警安排到第四機動隊的。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AGENCY_NPC_POLICE_NULL","text":{"KOREA":"순경? 아니야.","JPN":"巡査？　違うな。","ENG":"Constable? No, that won't do at all.","TWN":"巡警？不不。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"AGENCY_NPC_POLICE_NULL","text":{"KOREA":"얼마 만에 들어온 카운터 능력자인데 경정 배지 정도는 달아줘야 위신이 서지 않겠나?","JPN":"久しぶりのカウンター能力者だ。警視くらいじゃないと、メンツが立たないだろう。","ENG":"It's been too long since we've had a Counter join the force. We ought to make her at least a Major to save face, no?","TWN":"好不容易來了個制裁者，至少要戴個警正的徽章才威風啊，不是嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"INTERVIEWER_NPC_POLICE_NULL","text":{"KOREA":"겨, 경정이요? 이제 막 채용된 신입을요?","JPN":"け、警視？　採用したばかりの新米をですか？","ENG":"A M-Major? But we just hired her!","TWN":"警、警正？一個剛錄用的新人？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AGENCY_NPC_POLICE_NULL","text":{"KOREA":"그래. 참고로 말하자면 이것도 위에서 결정된 거야. 그러니까 거부는 거부하겠네.","JPN":"そうだ。ちなみに、これも上からの決定事項だから拒否権はない。","ENG":"You heard me. And just so you know, this decision comes from beyond my pay grade as well. So your objection is duly denied.","TWN":"對。以防萬一說一聲，這也是上面的決定，所以不接受拒絕喔。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};